    using namespace std;
    int main()
    {
    		long long int ans=0;
    		int x,n;
    		cin>>x>>n;
    		char ch;
    		scanf("%c",&ch);
    		while(n--)
    		{
    			char s[55];
    			scanf("%s",s);
    			//printf("%s\n",s);
    			int l=53,f=0;
    			for(int j=0;j<9;j++)
    			{
    				int c=0;
    				if(s[l]=='0')
    				c++;
    				if(s[l-1]=='0')
    				c++;
    				if(s[f]=='0')
    				c++;
    				if(s[f+1]=='0')
    				c++;	
    				if(s[f+2]=='0')
    				c++;
    				if(s[f+3]=='0')
    				c++;
    				//cout<<"c= "<<c<<endl;
    				if(c>=x)
    				{
    				    int z=1;
                        for(int i=0;i<x;i++)
      					{
    					    z=((z*(c-i))/(i+1));
    					}
    					//cout<<"c = "<<c<<" "<<"x = "<<x<<" "<<"z= "<<z<<endl;
    					ans=ans+z;
    				}
    				l=l-2;
    				f=f+4;
    			}

    		}
    	   cout<<ans<<endl;	
    	return 0;
    }
